    c.ATK_P = s0.y;
    c.DEF_P = s0.z;
    c.SPD_P = s0.w;

    c.HP    = s1.x;
    c.ATK   = s1.y;
    c.DEF   = s1.z;
    c.SPD   = s1.w;

    c.CR    = s2.x;
    c.CD    = s2.y;
    c.EHR   = s2.z;
    c.RES   = s2.w;

    c.BE    = s3.x;
    c.ERR   = s3.y;
    c.OHB   = s3.z;
    c.PHYSICAL_DMG_BOOST  = s3.w;

    c.FIRE_DMG_BOOST      = s4.x;
    c.ICE_DMG_BOOST       = s4.y;
    c.LIGHTNING_DMG_BOOST = s4.z;
    c.WIND_DMG_BOOST      = s4.w;

